#include "curl.h"

static CURLcode t1652_setup(struct Curl_easy **easy)
{
  CURLcode result = CURLE_OK;

  global_init(CURL_GLOBAL_ALL);
  *easy = curl_easy_init();
  if(!*easy) {
    curl_global_cleanup();
    return CURLE_OUT_OF_MEMORY;
  }
  return result;
}

static void t1652_stop(struct Curl_easy *easy)
{
  curl_easy_cleanup(easy);
  curl_global_cleanup();
}

static CURLcode test_unit1652(const char *arg)
{
  struct Curl_easy *easy;
  CURLcode result;

  UNITTEST_BEGIN(t1652_setup(&easy))

  /* Test setting HTTP/3 stream priority with urgency only */
  result = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, 3L);
  fail_unless(result == CURLE_OK, "Failed to set H3_STREAM_PRIORITY");

  /* Verify the values in the easy handle */
  fail_unless(easy->set.h3_priority_urgency == 3, "urgency not set correctly");
  fail_unless(easy->set.h3_priority_incremental == 0, "incremental should be 0");

  /* Test setting with incremental flag (bit 3 set) */
  result = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, (7 | 0x08));
  fail_unless(result == CURLE_OK, "Failed to set H3_STREAM_PRIORITY with incremental");

  /* Verify both values */
  fail_unless(easy->set.h3_priority_urgency == 7, "urgency not set correctly");
  fail_unless(easy->set.h3_priority_incremental == 1, "incremental should be 1");

  /* Test setting urgency 0 with incremental */
  result = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, 0x08);
  fail_unless(result == CURLE_OK, "Failed to set H3_STREAM_PRIORITY with urgency 0");

  fail_unless(easy->set.h3_priority_urgency == 0, "urgency should be 0");
  fail_unless(easy->set.h3_priority_incremental == 1, "incremental should be 1");

  UNITTEST_END(t1652_stop(easy))
}

UNITTEST_MAIN_LISTING(test_unit1652)

